IMG_SIZE   = 224
MODEL_PATH = '/content/lung_cancer_model.keras'
CATEGORIES = ['Lung Adenocarcinoma', 'Lung Normal', 'Lung Squamous Cell Carcinoma']

CLASS_INFO = {
    'Lung Adenocarcinoma': {
        'key':'adenocarcinoma','icon':'🔴','color':'#cc2828',
        'desc':'Malignant tumor originating in glandular cells of the lung periphery.',
        'accuracy':'96%','risk':'HIGH RISK','risk_bg':'rgba(200,40,40,0.12)','risk_color':'#cc2828',
    },
    'Lung Normal': {
        'key':'normal','icon':'🟢','color':'#00e676',
        'desc':'No malignant tissue detected. Tissue appears healthy.',
        'accuracy':'100%','risk':'NO RISK','risk_bg':'rgba(0,230,118,0.12)','risk_color':'#00e676',
    },
    'Lung Squamous Cell Carcinoma': {
        'key':'squamous','icon':'🟡','color':'#ffa01e',
        'desc':'Malignant tumor arising from squamous cells lining the airways.',
        'accuracy':'99%','risk':'HIGH RISK','risk_bg':'rgba(255,160,30,0.12)','risk_color':'#ffa01e',
    },
}

if 'history' not in st.session_state:
    st.session_state.history = []

@st.cache_resource(show_spinner=False)
def load_model():
    if os.path.exists(MODEL_PATH):
        try:
            return keras.models.load_model(MODEL_PATH)
        except Exception:
            # Keras version mismatch: patch InputLayer to accept legacy args
            import tensorflow as tf
            from keras.layers import InputLayer as _OrigInputLayer

            class _CompatInputLayer(_OrigInputLayer):
                def __init__(self, *args, **kwargs):
                    kwargs.pop("batch_shape", None)
                    kwargs.pop("optional", None)
                    super().__init__(*args, **kwargs)

            with tf.keras.utils.custom_object_scope({"InputLayer": _CompatInputLayer}):
                return keras.models.load_model(MODEL_PATH)
    vgg = vgg16.VGG16(weights='imagenet', include_top=False, input_shape=(IMG_SIZE,IMG_SIZE,3))
    vgg.trainable = False
    model = keras.Sequential([vgg,keras.layers.GlobalAveragePooling2D(),
        keras.layers.Dense(1024,activation='relu'),keras.layers.Dense(512,activation='relu'),
        keras.layers.Dense(3,activation='softmax')])
    model.compile(optimizer='adam',loss='sparse_categorical_crossentropy',metrics=['accuracy'])
    return model

def preprocess(image):
    img = image.convert('RGB').resize((IMG_SIZE, IMG_SIZE))
    arr = np.array(img).astype(np.float32)          # RGB, 0-255
    arr = np.expand_dims(arr, axis=0)               # add batch dim
    arr = vgg16.preprocess_input(arr)               # BGR + ImageNet zero-center
    return arr

def prob_bar(label,val,color):
    pct = val*100
    st.markdown(f"""<div class="prob-row">
      <div class="prob-top"><span>{label}</span>
        <span class="prob-pct" style="color:{color}">{pct:.1f}%</span></div>
      <div class="prob-bg"><div class="prob-fill" style="width:{pct}%;background:{color}"></div></div>
    </div>""", unsafe_allow_html=True)

